//defines to go go into h file
#define DELAY 300000
#define RCC_ADDR 0x40023800
#define AHB1_ENR_OFFSET 0x30

#define GPIOA_BASE_ADDR 0x40020000
#define GPIOB_BASE_ADDR 0x40020400
