/*------------------------------------------------------------------------------------------*/

int main(void)
{
	//rcc register clock needs to be turned on
	RCC_AHB1_s* ptr_rcc = (RCC_AHB1_s*)(RCC_ADDR + AHB1_ENR_OFFSET);

	//activate the ports
    ptr_rcc -> GPIOA_EN = 1;
    ptr_rcc -> GPIOB_EN = 1;
	ptr_rcc -> GPIOD_EN = 1;

	//create pointer to gpio port A memory
	GPIO_MODE_s* ptr_amode = (GPIO_MODE_s*)(GPIOA_BASE_ADDR + GPIO_MODE_OFFSET);
    //create pointer to gpio port B memory
    GPIO_MODE_s* ptr_bmode = (GPIO_MODE_s*)(GPIOB_BASE_ADDR + GPIO_MODE_OFFSET);
    //create pointer to gpio port D memory
	GPIO_MODE_s* ptr_dmode = (GPIO_MODE_s*)(GPIOD_BASE_ADDR + GPIO_MODE_OFFSET);

    //turn on input mode and output mode off port a
    ptr_amode -> MODER0 = 00;
    //turn off input mode and ouput mode on for port b
    ptr_bmode -> MODER10 = 01;
	//turn off input mode for D pin 12,13,14,15 & //turn on output node for D pin 12
	ptr_dmode -> MODER15 = 01;
    ptr_dmode -> MODER14 = 01;
    ptr_dmode -> MODER13 = 01;
    ptr_dmode -> MODER12 = 01;

    //create pointers for each pin output mode register
    GPIO_INPUT_DATA_s* ptr_inA = (GPIO_INPUT_DATA_s*)(GPIOA_BASE_ADDR + GPIO_INPUT);
    GPIO_OUTPUT_DATA_s* ptr_outB = (GPIO_OUTPUT_DATA_s*)(GPIOB_BASE_ADDR + GPIO_OUTPUT);
    GPIO_OUTPUT_DATA_s* ptr_outD = (GPIO_OUTPUT_DATA_s*)(GPIOD_BASE_ADDR + GPIO_OUTPUT);

	while (1)
	{
        //read data from button to var
        uint32_t button_sig = (ptr_inA->IDR0 & (1<<0))>>0;

        if (button_sig == 1)
        {
            //turn all leds on
        		for (int i = 0; i<DELAY; i++);
                ptr_outB -> ODR10 = 1;
                ptr_outD -> ODR12 = 1;
                ptr_outD -> ODR13 = 1;
                ptr_outD -> ODR14 = 1;
                ptr_outD -> ODR15 = 1;
                for (int i = 0; i<DELAY; i++);

                //turn all leds off
                for (int i = 0; i<DELAY; i++);
                ptr_outB -> ODR10 = 0;
                ptr_outD -> ODR12 = 0;
                ptr_outD -> ODR13 = 0;
                ptr_outD -> ODR14 = 0;
                ptr_outD -> ODR15 = 0;
                for (int i = 0; i<DELAY; i++);
          }//end if button on while

        else
        {
            //turn all leds off
            ptr_outB -> ODR10 = 0;
            ptr_outD -> ODR12 = 0;
            ptr_outD -> ODR13 = 0;
            ptr_outD -> ODR14 = 0;
            ptr_outD -> ODR15 = 0;
        }//end button off elif
	}//end main while
    /* Loop forever */
	for(;;);
}
